    //                 "ordId":"370257534141235201",
    //                 "ordType":"limit",
    //                 "pnl":"0",
    //                 "posSide":"",
    //                 "px":"60000",
    //                 "rebate":"0",
    //                 "rebateCcy":"ETH",
    //                 "reqId":"",
    //                 "side":"sell",
